class Solution:
    def findLongestChain(self, pairs):
        # O(n^2) DP independent of the greedy.
        ps = sorted(pairs, key=lambda p: p[0])
        n = len(ps)
        dp = [1] * n
        best = 1
        for i in range(n):
            for j in range(i):
                if ps[j][1] < ps[i][0] and dp[j] + 1 > dp[i]:
                    dp[i] = dp[j] + 1
            best = max(best, dp[i])
        return best

