class Solution:
    def findLongestChain(self, pairs):
        pairs.sort(key=lambda p: p[1])
        count = 0
        cur_end = float('-inf')
        for a, b in pairs:
            if a > cur_end:
                count += 1
                cur_end = b
        return count

