var findLongestChain = function(pairs) {
    pairs.sort((x, y) => x[1] - y[1]);
    let count = 0;
    let curEnd = -Infinity;
    for (const [a, b] of pairs) {
        if (a > curEnd) {
            count++;
            curEnd = b;
        }
    }
    return count;
};
